@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">@ChildContent</div>

@code {
    /// <summary>Tailwind <c>max-w-*</c> size token (e.g. <c>sm</c>, <c>lg</c>, <c>4xl</c>) applied as
    /// <c>max-w-{MaxWidth}</c>. Set to null/empty to render without a max width. Default: <c>"lg"</c>.</summary>
    [Parameter] public string? MaxWidth { get; set; } = "lg";
    /// <summary>Horizontally centers the container within its parent via <c>mx-auto</c>. Default: true.</summary>
    [Parameter] public bool Center { get; set; } = true;
    /// <summary>Tailwind spacing token applied as horizontal padding (<c>px-{Padding}</c>). Set to
    /// null/empty for no horizontal padding. Default: <c>"4"</c>.</summary>
    [Parameter] public string? Padding { get; set; } = "4";
    /// <summary>The container's content.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the root <c>div</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Additional HTML attributes captured and forwarded to the root <c>div</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass
    {
        get
        {
            var maxWidth = !string.IsNullOrEmpty(MaxWidth) ? $"max-w-{MaxWidth}" : "";
            var center = Center ? "mx-auto" : "";
            var padding = !string.IsNullOrEmpty(Padding) ? $"px-{Padding}" : "";
            return Cx.Merge("w-full", maxWidth, center, padding, Class);
        }
    }
}
